$base = "C:\Users\Nel\Desktop\Curso de Front End 2026\Agricultura Antigua para HOY\Agricultura Antigua1\src\data"
$MAX_BATCH_SIZE = 100
$MAX_TOTAL = 300

function Write-QAFile($entries, $fileNum) {
    $filename = "comunidad-qa$fileNum.ts"
    $path = Join-Path $base $filename
    $varName = "COMMUNITY_QA_$fileNum"
    
    $lines = @()
    $lines += "import type { CommunityPost } from '../types';"
    $lines += ""
    $lines += "export const $varName`: CommunityPost[] = ["
    
    foreach ($e in $entries) {
        $parts = $e -split '\|', 4
        $num = $parts[0]
        $cat = $parts[1]
        $q = $parts[2] -replace "'", "\'"
        $a = $parts[3] -replace "'", "\'"
        $likes = Get-Random -Min 10 -Max 30
        
        $lines += "  {"
        $lines += "    id: `"qa-$num`","
        $lines += "    title: '$q',"
        $lines += "    category: `"$cat`","
        $lines += "    author: 'Agricultor Orgánico',"
        $lines += "    content: '$q',"
        $lines += "    date: `"Hace $(($num % 5) + 2) días`","
        $lines += "    likes: $likes,"
        $lines += "    replies: [{"
        $lines += "      id: `"qar-$num`","
        $lines += "      author: 'MSc. Agroecología',"
        $lines += "      content: '$a',"
        $lines += "      date: `"Hace $(($num % 5) + 1) días`""
        $lines += "    }]"
        $lines += "  },"
    }
    $lines += "];"
    
    $lines -join "`n" | Set-Content -Path $path -Encoding UTF8
    Write-Host "Created $filename with $($entries.Count) entries"
}

# Categories: Suelos, Plagas, Bioinsumos, Casos de Éxito, Intercambio de Semillas

# ═══════════════════ PREGUNTAS 601-700 ═══════════════════
$p601_700 = @(
"601|Bioinsumos|¿Por qué la aplicación de Biotaplus en el cultivo de ajo ayuda a mejorar la conformación de los dientes y el cierre de la cabeza?|Porque estimula una movilización eficiente de fotoasimilados desde las hojas hacia el bulbo durante la etapa de diferenciación. Esto asegura que los dientes se desarrollen compactos, con turgencia y que las túnicas protectoras externas se cierren con firmeza, mejorando su calidad comercial y post-cosecha."
"602|Suelos|¿Cómo influye la relación Carbono/Nitrógeno (C/N) de una enmienda orgánica en la velocidad de liberación de nutrientes en el suelo?|Si la relación C/N es baja (menor a 15), la descomposición es rápida y libera nitrógeno disponible. Si es alta (mayor a 30), los microorganismos consumen el nitrógeno del suelo para degradar el carbono, bloqueándolo temporalmente."
"603|Suelos|¿Qué es el punto de marchitez temporal en las hortalizas de hoja y en qué se diferencia del permanente?|El temporal ocurre en las horas de mayor calor cuando la transpiración supera la absorción, pero la planta se recupera. El permanente (PMP) es irreversible: la planta no recupera turgencia porque el suelo no tiene agua extraíble."
"604|Bioinsumos|¿Por qué el jabón potásico es un excelente aliado para ablandar el agua dura antes de agregar otros bioinsumos compatibles?|Actúa como agente secuestrante que precipita parte del calcio y magnesio libres, ablandando el agua y mejorando la solubilidad y estabilidad de otros extractos botánicos o bioestimulantes."
"605|Suelos|¿Qué es la solarización y bajo qué condiciones climáticas de Chile se puede realizar con alta efectividad?|Es la desinfección física cubriendo el suelo húmedo con plástico transparente. En Chile es efectiva en zona norte y central durante diciembre-febrero, alcanzando temperaturas letales para patógenos en los primeros 20 cm."
"606|Bioinsumos|¿Cómo ayuda la aplicación foliar de sílice (Si) a mitigar el ataque de trips y ácaros en el cultivo de cebolla?|El sílice se deposita en las paredes celulares formando una capa dura de fitolitos que dificulta mecánicamente que trips raspen el tejido y ácaros succionen savia."
"607|Suelos|¿Por qué el exceso de riego por goteo en suelos arcillosos puede provocar anoxia radicular en lechugas recién plantadas?|Los suelos arcillosos tienen baja macroporosidad. El exceso de riego satura los poros, desplazando el oxígeno. Sin oxígeno, las raíces no respiran, detienen su crecimiento y se pudren."
"608|Suelos|¿Qué es la fisiopatía del corazón negro (blackheart) en el apio y qué nutriente está directamente involucrado?|Es la necrosis de las hojas jóvenes del centro que se tornan negras. Está directamente involucrada la deficiencia de calcio (Ca), gatillada por crecimiento rápido estimulado por excesos de nitrógeno o riegos irregulares."
"609|Bioinsumos|¿Por qué el jabón potásico no tiene un intervalo de seguridad o período de carencia antes de la cosecha?|Porque está compuesto por sales potásicas de ácidos grasos que se degradan rápidamente con luz y aire en compuestos inofensivos. No deja residuos tóxicos, permitiendo cosechar el mismo día de la aplicación."
"610|Plagas|¿Qué es un nemátodo fitoparásito y qué síntoma característico produce en las raíces de la betarraga?|Es un gusano microscópico que penetra y se alimenta de las raíces. Produce protuberancias, deformaciones o agallas en las raíces secundarias y principales, reduciendo la absorción de nutrientes y deformando la raíz comercial."
"611|Suelos|¿Qué es la capacidad de campo (CC) de un suelo y por qué es el estado ideal para los cultivos?|Es el contenido de agua que retiene el suelo tras drenar el exceso por gravedad. Es ideal porque los poros pequeños están llenos de agua disponible y los grandes de aire, equilibrando agua y oxígeno."
"612|Bioinsumos|¿Por qué la aplicación de Biotaplus ayuda a los cultivos de lechuga a sobrellevar el estrés por trasplante?|Biotaplus aporta fitohormonas naturales y aminoácidos que estimulan la división celular y emisión de raíces adventicias, permitiendo que la plántula restablezca sus pelos absorbentes y reanude el crecimiento rápidamente."
"613|Suelos|¿Cuál es la diferencia visual entre la deficiencia de Nitrógeno (N) y la deficiencia de Azufre (S) en hortalizas?|La deficiencia de nitrógeno aparece primero en hojas viejas (nutriente móvil). La de azufre, al ser poco móvil, aparece primero en hojas jóvenes del ápice."
"614|Suelos|¿Por qué la labranza excesiva con rotovator destruye la estructura física a largo plazo del suelo?|Pulveriza los agregados naturales, rompiendo macro y microporos. Además acelera la oxidación de materia orgánica al exponerla al aire, facilitando la formación de costras duras en la superficie."
"615|Bioinsumos|¿Qué es un bioplaguicida a base de bacterias y cómo actúa Bacillus thuringiensis contra larvas de polillas?|Es un pesticida biológico. Bacillus thuringiensis produce proteínas cristalinas (delta-endotoxinas) que al ser ingeridas por la larva se activan en su intestino alcalino, perforando las paredes intestinales y causando muerte por septicemia."
"616|Suelos|¿Por qué la presencia de sales de sodio (Na+) en el suelo degrada físicamente la estructura de los suelos arcillosos?|El sodio provoca la dispersión de las arcillas, separando las partículas que taponan los poros, volviendo el suelo denso, impermeable y extremadamente duro al secarse."
"617|Suelos|¿Cómo influye la temperatura del suelo en la absorción del fósforo (P) por parte de las hortalizas de invierno?|Las bajas temperaturas (menos de 12 °C) disminuyen la actividad metabólica de las raíces y la solubilidad del fósforo, reduciendo su absorción hasta en un 70%."
"618|Plagas|¿Qué es la pudrición de raíz por Phytophthora y qué manejo cultural ayuda a prevenirla en tomates?|Es causada por un oomiceto que pudre cuello y raíces, marchitando la planta. Se previene con camellones altos, control de riego para evitar encharcamientos y desinfección de herramientas."
"619|Suelos|¿Por qué el uso de coberturas plásticas (mulch) de color negro ayuda a controlar las malezas sin usar herbicidas?|El plástico negro impide el paso de luz solar. Las semillas bajo él no pueden fotosintetizar, agotando sus reservas y muriendo."
"620|Suelos|¿Qué papel juegan las citoquininas en la vida post-cosecha de hortalizas como espinaca o acelga?|Retrasan la senescencia foliar manteniendo estables las membranas celulares, conservando la clorofila y evitando la degradación de proteínas, prolongando la frescura."
"621|Bioinsumos|¿Qué es la asociación beneficiosa entre el hongo Trichoderma harzianum y las raíces de las plantas?|Trichoderma coloniza la rizosfera, actuando mediante micoparasitismo (destruye hongos patógenos), compite por espacio y nutrientes, induce defensas naturales y estimula el desarrollo radicular."
"622|Suelos|¿Por qué la falta de potasio (K) disminuye la tolerancia de las plantas a los periodos de sequía?|El potasio regula la apertura y cierre estomático. Sin suficiente K, las células oclusivas cierran los estomas lenta e ineficientemente, perdiendo agua por transpiración descontrolada."
"623|Plagas|¿Qué es la humedad relativa (HR) y por qué valores superiores al 90% en invernadero favorecen a Botrytis cinerea?|Es el vapor de agua en el aire respecto al máximo posible. HR >90% evita la evaporación de agua libre y genera condensación, condiciones perfectas para que esporas de Botrytis germinen."
"624|Plagas|¿Cómo afecta la aplicación de fertilizantes nitrogenados en exceso a la susceptibilidad de las plantas al ataque de pulgones?|El exceso de N genera tejidos tiernos, suculentos y con alta concentración de aminoácidos libres en savia, haciéndolos muy atractivos para insectos chupadores como pulgones."
"625|Plagas|¿Qué es la pudrición blanda bacteriana (Erwinia carotovora) en papas y betarragas y cómo se identifica?|Es una enfermedad bacteriana que desintegra los tejidos internos en una masa mucosa blanda con olor fétido penetrante."
"626|Bioinsumos|¿Por qué la aplicación de extractos de ortiga (Urtica dioica) funciona como bioestimulante y repelente?|Es rico en nitrógeno orgánico, silicio, hierro y ácidos orgánicos que fortalecen la pared celular. Sus compuestos volátiles actúan como repelente natural contra pulgones y ácaros."
"627|Suelos|¿Qué es el coeficiente de uniformidad (CU) en riego por goteo y por qué debe medirse periódicamente?|Mide el porcentaje de uniformidad del agua aplicada por los goteros. Debe medirse para detectar goteros tapados, variaciones de presión o desgaste que causen riego desigual."
"628|Suelos|¿Cómo influye el pH del suelo en la disponibilidad del zinc (Zn) para los cultivos hortícolas?|A pH >7.5 (suelos alcalinos/calcáreos), el zinc forma hidróxidos y carbonatos insolubles, induciendo clorosis y retrasos por falta de síntesis de auxinas."
"629|Suelos|¿Qué es el mulch vivo en la agricultura orgánica y qué ventajas aporta al suelo entre hileras?|Es sembrar un cultivo de cobertura rastrero entre las hileras. Controla malezas por competencia, fija nitrógeno, retiene humedad y protege contra la erosión."
"630|Suelos|¿Por qué la betarraga requiere un suelo bien provisto de boro (B) y qué síntoma visual delata su deficiencia?|El boro es clave para transporte de azúcares e integridad celular. Su deficiencia causa corazón negro: la raíz se torna seca, agrietada, marrón oscura con sabor amargo."
"631|Plagas|¿Qué es el mildiú y en qué se diferencia visualmente del oídio en hojas de zapallo italiano?|El mildiú produce manchas cloróticas angulares en el haz y vello grisáceo en el envés. El oídio produce polvo blanco algodonoso y superficial en ambas caras."
"632|Bioinsumos|¿Por qué se recomienda aplicar bioestimulantes a base de micorrizas al momento de la siembra o trasplante?|La colonización requiere varias semanas. Si se aplica al inicio, el hongo acompaña el crecimiento radicular desde el nacimiento, otorgando protección y absorción óptima desde el principio."
"633|Suelos|¿Qué es la escorrentía superficial y cómo la vegetación nativa en bordes de campos la reduce?|Es el flujo de agua sobre la superficie sin infiltrarse. La vegetación frena la velocidad del agua, facilita la infiltración y retiene sedimentos y nutrientes."
"634|Suelos|¿Cómo afecta el estrés por salinidad a la fotosíntesis neta de una planta de lechuga?|Las altas sales dificultan la absorción de agua. Para conservar agua, la lechuga cierra estomas, reduciendo la entrada de CO2 y frenando la fotosíntesis."
"635|Bioinsumos|¿Qué es un quelato y por qué los micronutrientes en fertirriego deben estar quelatados?|Un quelato protege al ion metálico evitando que reaccione e insolubilice. Al estar quelatados, los nutrientes permanecen solubles y disponibles para la raíz pese a variaciones de pH."
"636|Suelos|¿Por qué se debe evitar el uso de aguas de riego con altos niveles de boro y qué síntomas produce?|El boro tiene rango estrecho entre deficiencia y toxicidad. El exceso causa quemaduras necróticas en bordes y puntas de hojas viejas, reduciendo el área fotosintética."
"637|Suelos|¿Qué es la humedad de suelo a Punto de Marchitez Permanente (PMP) en términos de tensión?|Es el contenido de agua cuando la tensión de retención alcanza aproximadamente -15 bares (-1.5 MPa). A esta presión las raíces ya no pueden extraer agua."
"638|Bioinsumos|¿Por qué el jabón potásico es compatible para aplicaciones conjuntas con aceite de neem?|El jabón emulsiona el aceite de neem en agua. Potencian su acción porque el jabón elimina la cera del insecto, facilitando la penetración de los limonoides del neem."
"639|Suelos|¿Qué es la estructura del suelo y por qué determina la porosidad total?|Es la forma en que las partículas se agrupan en agregados. El espacio entre agregados (macro y microporos) define la capacidad de almacenar aire y agua."
"640|Suelos|¿Por qué la deficiencia de magnesio (Mg) produce clorosis intervenal en hojas viejas?|El magnesio es el átomo central de la clorofila. Al ser móvil, ante deficiencia la planta degrada clorofila de hojas viejas para enviar Mg a brotes nuevos."
"641|Plagas|¿Qué es el mosaico del pepino (CMV) y qué rango de hospedantes hortícolas afecta?|Es un virus transmitido por pulgones. Afecta solanáceas, umbelíferas, asteráceas y leguminosas, causando mosaicos amarillos y deformación de frutos."
"642|Suelos|¿Por qué el exceso de enmiendas orgánicas ricas en fósforo puede bloquear la absorción de zinc?|El exceso de fosfato reacciona con el zinc formando fosfato de zinc, un compuesto insoluble que precipita y no puede ser absorbido por las raíces."
"643|Bioinsumos|¿Qué es el lavado de raíces en hidroponía y por qué se realiza antes de la cosecha de lechugas?|Consiste en circular agua limpia sin fertilizantes 24-48 horas antes de cosechar para reducir nitratos en las hojas, mejorando sabor y seguridad alimentaria."
"644|Bioinsumos|¿Por qué la aplicación de extractos de ajo (Allium sativum) funciona como repelente de plagas?|El ajo es rico en alicina y compuestos azufrados volátiles que enmascaran los olores de atracción de las hortalizas, desorientando a trips y mosquitas blancas."
"645|Plagas|¿Qué es la pudrición radicular por Pythium y por qué ataca principalmente en almácigos?|Es un oomiceto con zoosporas móviles. Ataca almácigos porque las plántulas tienen tejidos epidérmicos delgados sin defensas lignificadas, facilitando la penetración."
"646|Bioinsumos|¿Cómo ayuda la aplicación de Biotaplus vía riego a mejorar la estructura física de la rizosfera en suelos arcillosos?|Biotaplus aporta prebióticos que alimentan bacterias benéficas. Estas secretan polisacáridos que aglutinan las arcillas en agregados estables, mejorando porosidad y drenaje."
"647|Suelos|¿Por qué el nitrógeno en forma de urea requiere temperaturas de suelo templadas para ser aprovechado?|La urea debe convertirse a amonio mediante la enzima ureasa microbiana. Esta actividad es lenta a temperaturas menores a 10 °C."
"648|Casos de Éxito|¿Qué es la fisiopatía de la flor doble o deforme en el tomate y qué condiciones la favorecen?|Es el desarrollo de flores deformes que dan frutos con caras de gato. Favorecida por temperaturas nocturnas menores a 12 °C durante la diferenciación floral."
"649|Bioinsumos|¿Por qué el uso de jabón potásico es compatible con programas de producción limpia (BPA) en Chile?|Es biodegradable, no acumulativo, exento de LMR, seguro para aplicadores y consumidores, facilitando cumplir estándares de Buenas Prácticas Agrícolas."
"650|Suelos|¿Qué es la profundidad de siembra y cuál es la regla general para semillas de hortalizas?|Es la distancia bajo la superficie a la que se coloca la semilla. Regla general: 2 a 3 veces su propio diámetro. Mayor profundidad agota las reservas antes de emerger."
"651|Suelos|¿Qué provoca el síntoma de tallo agrietado y retorcido en plantas de betarraga dulce?|Deficiencia severa de boro (B). El boro mantiene la plasticidad celular; sin él, los tejidos se vuelven quebradizos y se agrietan ante presiones de turgencia."
"652|Suelos|¿Por qué el uso de camellones con pendiente suave en riego por surco evita la salinización de la zona de raíces?|El agua asciende por capilaridad a la coronilla donde se evapora, depositando sales lejos de donde se trasplanta la lechuga (hombros del camellón)."
"653|Plagas|¿Qué es el mosaico amarillo del poroto (BYMV) y cómo se previene?|Es un virus transmitido por pulgones. Se previene eliminando malezas hospederas fabáceas en bordes y aplicando controladores biológicos contra pulgones tempranamente."
"654|Suelos|¿Por qué la aplicación foliar de calcio debe dirigirse a frutos o puntos de crecimiento jóvenes?|El calcio se mueve por xilema con la transpiración. Frutos y hojas del corazón transpiran poco, por lo que la aspersión debe mojarlos directamente para absorción in situ."
"655|Suelos|¿Qué es la capa de ozono del suelo o mantillo de hojas y cómo beneficia a la microbiología?|Es la hojarasca en descomposición que cubre el suelo. Protege contra radiación UV, conserva humedad superficial y provee fuente continua de carbono."
"656|Suelos|¿Por qué se debe regular el caudal y presión en riego para evitar deslavado de nutrientes por fertirriego?|Si el volumen supera la CRAD, el exceso arrastra nutrientes móviles como nitrógeno y potasio fuera del alcance de las raíces."
"657|Plagas|¿Qué es la antracnosis y qué daños estéticos produce en frutos de pimiento?|Es causada por Colletotrichum spp. Produce lesiones hundidas acuosas que se cubren de esporas rosadas, arruinando el valor estético del fruto."
"658|Bioinsumos|¿Por qué el jabón potásico con extracto de canela potencia el control sobre ácaros (arañita roja)?|El jabón disuelve la cutícula del ácaro, permitiendo que el cinamaldehído de la canela penetre como neurotoxina y desecante letal."
"659|Suelos|¿Qué es la textura del suelo y por qué se considera una propiedad inalterable?|Es la proporción de arena, limo y arcilla. Depende del material geológico de origen y meteorización a lo largo de miles de años; las prácticas agrícolas no la cambian."
"660|Suelos|¿Por qué la deficiencia de hierro (Fe) produce clorosis en hojas jóvenes pero mantiene las nervaduras verdes?|El hierro es inmóvil en la planta. Al no poder traslocarse de hojas viejas, las nuevas sufren falta de Fe, perdiendo color en tejido intervenal pero conservándolo en nervaduras."
"661|Plagas|¿Qué es la marchitez bacteriana (Ralstonia solanacearum) y qué hortalizas chilenas son susceptibles?|Bacteria vascular que tapona el xilema provocando marchitez súbita. Son susceptibles solanáceas como papa, tomate y berenjena."
"662|Bioinsumos|¿Por qué la aplicación de Biotaplus mejora la calidad de la lechuga en sistema hidropónico NFT?|Biotaplus mejora el desarrollo radicular, optimiza la asimilación de nutrientes y previene acumulación de nitratos, logrando hojas más turgentes y crujientes."
"663|Bioinsumos|¿Qué es la quimigación y qué precauciones de seguridad se deben tomar?|Es la aplicación de productos a través del riego. La precaución principal es instalar válvulas antirretorno para evitar contaminación de la fuente de agua."
"664|Suelos|¿Por qué el laboreo continuo con arado de vertedera genera el problema de pie de arado?|La presión constante a 20-25 cm compacta las partículas formando una capa densa e impermeable que impide drenaje y paso de raíces."
"665|Suelos|¿Qué es la lixiviación de nitratos y por qué es pérdida económica y amenaza ambiental?|Es el lavado de nitratos al subsuelo por exceso de agua. Pérdida económica por el N pagado; amenaza ambiental porque contamina napas freáticas."
"666|Plagas|¿Cómo ayudan las trampas cromotrópicas amarillas a monitorear moscas minadoras en tomates?|Los adultos de Liriomyza son atraídos por el amarillo brillante. Al volar a las trampas quedan atrapados, permitiendo estimar densidad poblacional."
"667|Suelos|¿Qué es la humectación por capilaridad en almácigos flotantes y qué ventaja tiene?|El sustrato absorbe agua ascendente desde una piscina inferior. No moja las hojas tiernas, eliminando humedad foliar que propicia hongos."
"668|Bioinsumos|¿Por qué la aplicación foliar de aminoácidos libres ahorra energía metabólica a la planta bajo estrés?|En condiciones normales la planta gasta ATP en transformar N mineral en aminoácidos. Al aplicarlos foliar, los absorbe directamente sin ese gasto energético."
"669|Plagas|¿Qué es la podredumbre blanca (Sclerotium cepivorum) en cebollas y ajos y por qué es tan persistente?|Pudre bulbos cubriéndolos con micelio blanco y esclerocios negros que permanecen viables en el suelo hasta 15-20 años."
"670|Plagas|¿Por qué la aplicación de jabón potásico ayuda a controlar cochinillas algodonosas (Planococcus spp.)?|Las cochinillas se protegen con secreciones cerosas. El jabón rompe esta capa, dejando expuesto el insecto y provocando su deshidratación."
"671|Suelos|¿Qué es la porosidad de aireación de un suelo y cuál es el porcentaje mínimo recomendado?|Es la fracción de macroporos que se llenan de aire a capacidad de campo. El mínimo recomendado es 10-12% del volumen del suelo."
"672|Suelos|¿Por qué evitar aguas con alta Conductividad Eléctrica (CE) en almácigos de hortalizas?|Los almácigos tienen raíces delicadas. Alta CE eleva la presión osmótica, impidiendo la absorción de agua e induciendo quemaduras en raíces."
"673|Plagas|¿Qué es la enfermedad de la mancha de chocolate en habas y qué hongo la produce?|Producida por Botrytis fabae en clima fresco y húmedo. Produce manchas circulares rojizas o marrón chocolate en hojas, tallos y flores."
"674|Bioinsumos|¿Por qué los extractos de algas ricos en betaínas estabilizan la clorofila de lechugas bajo frío?|Las betaínas son osmoprotectores que protegen membranas y enzimas de cloroplastos contra temperaturas extremas, evitando la degradación de clorofila."
"675|Suelos|¿Qué es el moteado clorótico y qué deficiencia lo causa en hojas de poroto?|Son pequeñas manchas amarillas difusas. Causado por deficiencia de manganeso (Mn) o zinc (Zn) en suelos con pH elevado."
"676|Suelos|¿Por qué el viento de goteo minimiza pérdidas de agua por evaporación en climas cálidos?|Al gotear bajo el follaje, se reduce el área de suelo húmedo expuesta al sol y la turbulencia, optimizando el consumo eficiente del agua."
"677|Suelos|¿Qué es la solarización plástica doble y qué beneficio ofrece?|Dos capas de plástico separadas por cámara de aire. Eleva la temperatura 3-6 °C más que la simple, mejorando la desinfección a mayor profundidad."
"678|Suelos|¿Por qué la adición de compost incrementa la CRAD en suelos arenosos?|El humus actúa como esponja biológica con enorme superficie específica y cargas que retienen agua por cohesión y adhesión en microporos."
"679|Bioinsumos|¿Qué es la fitotoxicidad por sobredosis de jabón potásico y qué síntomas produce?|Ocurre a concentraciones >3% v/v o en calor extremo. Produce quemaduras necróticas en bordes de hojas y amarillamiento por disolución de la cutícula."
"680|Suelos|¿Por qué el potasio es fundamental para la translocación de azúcares en la betarraga?|El potasio activa enzimas clave y proporciona el gradiente electroquímico en el floema necesario para bombear azúcares hacia la raíz de reserva."
"681|Plagas|¿Qué es la enfermedad del pie negro (Phoma lingam) en repollos y cómo sobrevive?|Pudre el tallo a nivel del cuello volviéndolo negro. Sobrevive como esporas y micelio en rastrojos de brasicáceas de cosechas anteriores."
"682|Bioinsumos|¿Por qué la aplicación de Biotaplus potencia los rendimientos del tomate bajo invernadero?|Estimula el desarrollo radicular y la absorción de nutrientes, mejorando la turgencia y fotosíntesis. Se traduce en mayor amarre de flores y calibre de frutos."
"683|Plagas|¿Qué es el mosaico de la sandía (WMV-2) y qué vector lo transmite en zapallo italiano?|Virus que deforma hojas y causa verrugas en frutos. Transmitido por pulgones de forma no persistente al picar las hojas."
"684|Suelos|¿Por qué los suelos calcáreos limitan severamente la disponibilidad de fósforo?|En suelos alcalinos, el fosfato reacciona con el calcio formando fosfato tricálcico insoluble que precipita y queda bloqueado."
"685|Plagas|¿Qué es la pudrición carbonosa del tallo en porotos y qué condiciones la detonan?|Causada por Macrophomina phaseolina. Detonada por temperaturas >30 °C combinadas con estrés por sequía en suelos compactados."
"686|Suelos|¿Por qué la aplicación foliar de zinc debe realizarse temprano en la mañana?|Con alta humedad y temperaturas templadas, los estomas están abiertos y la gota no se seca rápido, permitiendo mayor absorción por difusión foliar."
"687|Suelos|¿Qué es la biodesodorización en el compostaje de estiércoles?|Eliminación de olores ofensivos asegurando correcta aireación y relación C/N que permita a bacterias aeróbicas retener compuestos olorosos sin liberarlos."
"688|Suelos|¿Por qué la compactación reduce el volumen de suelo explorado por raíces de betarraga?|Las raíces requieren poros con baja resistencia. En suelo compactado, la densidad es alta y los poros estrechos, confinando las raíces a la superficie."
"689|Suelos|¿Qué es la malla sombra y en qué fase de la lechuga de verano ayuda a evitar el sabor amargo?|Malla que filtra radiación. Ayuda en madurez comercial reduciendo estrés térmico, evitando acumulación defensiva de lactucina (compuesto amargo)."
"690|Suelos|¿Por qué evitar el trasplante profundo (cuello enterrado) en lechugas?|El cuello es tierno y no soporta humedad constante. Enterrarlo favorece patógenos como Rhizoctonia o Pythium y provoca asfixia tisular."
"691|Suelos|¿Qué es la humedad aprovechable (HA) y qué porcentaje se aconseja agotar antes del siguiente riego?|Agua entre CC y PMP. En hortalizas de raíz poco profunda como lechuga, se aconseja agotar máximo 30-40% antes de regar."
"692|Bioinsumos|¿Por qué el jabón potásico es de amplio espectro pero selectivo por tipo de plaga?|Elimina físicamente varias especies de cuerpo blando, pero no afecta insectos de cuerpo duro como chinitas o abejas adultas."
"693|Suelos|¿Qué es el coeficiente de transpiración de un cultivo y qué hortaliza tiene uno elevado?|Agua que la planta debe transpirar para producir 1 kg de materia seca. Apio y lechuga tienen coeficientes extremadamente elevados."
"694|Suelos|¿Por qué el exceso de N nítrico en fertirriego disminuye la absorción de potasio y calcio?|Estimula crecimiento vegetativo acelerado que consume rápidamente las reservas, diluyendo la concentración de K+ y Ca2+ disponibles."
"695|Plagas|¿Qué provoca la mancha púrpura en hojas de cebolla (Alternaria porri)?|Hongo Alternaria porri en clima templado y alta humedad foliar. Daña el follaje afectando el tamaño final del bulbo."
"696|Bioinsumos|¿Por qué los bioestimulantes con ácido salicílico preparan a las plantas para sequía?|El ácido salicílico induce acumulación preventiva de antioxidantes, cierre parcial de estomas y fortalecimiento de membranas antes de la sequía real."
"697|Plagas|¿Qué es la pudrición del cuello por Sclerotinia sclerotiorum en porotos?|Pudre cuello y vainas bajas, cubriéndolos de micelio blanco algodonoso con esclerocios negros."
"698|Bioinsumos|¿Por qué Biotaplus favorece la disponibilidad de hierro nativo bloqueado?|Estimula bacterias productoras de sideróforos que quelan el hierro insoluble del suelo, transformándolo en forma soluble para las raíces."
"699|Bioinsumos|¿Qué es la tensión superficial del agua y cómo la reduce el jabón potásico?|Fuerza que mantiene unidas las moléculas de agua en una gota. El jabón rompe esta fuerza, permitiendo que la gota se extienda y moje toda la hoja."
"700|Plagas|¿Qué es el mosaico de la coliflor (CaMV) y qué característica genética tiene?|Afecta coliflor, repollo y brócoli. Su genoma es ADN de doble cadena (inusual en virus de plantas) y es transmitido por pulgones."
)

